<?php
if (!function_exists('hr_t')) {
  function hr_t($key, $fallback = '') { return lang_text($key, $fallback); }
}
if (!function_exists('hr_h')) {
  function hr_h($key, $fallback = '') { return htmlspecialchars((string) hr_t($key, $fallback), ENT_QUOTES, 'UTF-8'); }
}
if (!function_exists('hr_js')) {
  function hr_js($key, $fallback = '') { return json_encode(hr_t($key, $fallback), JSON_HEX_TAG | JSON_HEX_APOS | JSON_HEX_AMP | JSON_HEX_QUOT); }
}
if (session_status() === PHP_SESSION_NONE) session_start();
include "../../inc/config.php";
session_check_json();
function srd_h($v){return htmlspecialchars((string)$v,ENT_QUOTES,'UTF-8');}
function srd_label($s,$type='status'){$m=$type==='decision'?array('PENDING'=>'default','SELECTED'=>'success','REJECTED'=>'danger','HOLD'=>'warning','WAITING_LIST'=>'info','REINTERVIEW'=>'primary'):array('DRAFT'=>'default','SUBMITTED'=>'warning','APPROVED'=>'success','REJECTED'=>'danger','CANCELLED'=>'default');$c=isset($m[$s])?$m[$s]:'default';return '<span class="label label-'.$c.'">'.srd_h($s).'</span>';}
function srd_filters(){return array('from'=>isset($_POST['tgl_awal'])&&$_POST['tgl_awal']!==''?$_POST['tgl_awal']:date('Y-m-01'),'to'=>isset($_POST['tgl_akhir'])&&$_POST['tgl_akhir']!==''?$_POST['tgl_akhir']:date('Y-m-t'),'status'=>isset($_POST['selection_status'])?trim($_POST['selection_status']):'','decision'=>isset($_POST['decision_result'])?trim($_POST['decision_result']):'','stage'=>isset($_POST['selection_stage'])?trim($_POST['selection_stage']):'','vacancy_id'=>isset($_POST['vacancy_id'])?trim($_POST['vacancy_id']):'','keyword'=>isset($_POST['keyword'])?trim($_POST['keyword']):'');}
function srd_where($f,&$p){$w=" WHERE s.selection_date BETWEEN ? AND ? ";array_push($p,$f['from'],$f['to']);if($f['status']!==''){$w.=" AND s.selection_status=? ";$p[]=$f['status'];}if($f['decision']!==''){$w.=" AND s.decision_result=? ";$p[]=$f['decision'];}if($f['stage']!==''){$w.=" AND s.selection_stage=? ";$p[]=$f['stage'];}if($f['vacancy_id']!==''){$w.=" AND s.vacancy_id=? ";$p[]=(int)$f['vacancy_id'];}if($f['keyword']!==''){$kw='%'.$f['keyword'].'%';$w.=" AND (s.selection_no LIKE ? OR a.applicant_no LIKE ? OR a.applicant_name LIKE ? OR v.vacancy_no LIKE ? OR v.vacancy_title LIKE ?) ";array_push($p,$kw,$kw,$kw,$kw,$kw);}return $w;}
$draw=isset($_POST['draw'])?(int)$_POST['draw']:1;$start=isset($_POST['start'])?max(0,(int)$_POST['start']):0;$length=isset($_POST['length'])?(int)$_POST['length']:25;if($length<=0||$length>500)$length=25;
$f=srd_filters();$p=array();$w=srd_where($f,$p);$base=" FROM erp_selection_result s LEFT JOIN erp_applicant_data a ON a.id=s.applicant_id LEFT JOIN erp_job_vacancy v ON v.id=s.vacancy_id LEFT JOIN erp_interview_schedule i ON i.id=s.final_interview_id LEFT JOIN erp_employee_master app ON app.id=s.approved_by_employee_id ";
$kpi=$db->fetch("SELECT COUNT(*) total,SUM(s.decision_result='SELECTED') selected_count,SUM(s.decision_result='REJECTED') rejected_count,SUM(s.decision_result IN ('HOLD','WAITING_LIST')) hold_count,SUM(s.selection_status='APPROVED') approved_count,AVG(NULLIF(s.overall_score,0)) avg_score $base $w",$p);
$cnt=$db->fetch("SELECT COUNT(*) jml $base $w",$p);$total=$cnt?(int)$cnt->jml:0;
$orderMap=array(2=>'s.selection_no',3=>'a.applicant_name',4=>'v.vacancy_no',5=>'s.selection_stage',6=>'s.overall_score',7=>'s.decision_result',8=>'s.selection_status',9=>'s.proposed_salary',10=>'s.updated_at');$orderBy='s.selection_date DESC,s.selection_no DESC';
if(isset($_POST['order'][0]['column'])){$col=(int)$_POST['order'][0]['column'];$dir=(isset($_POST['order'][0]['dir'])&&strtolower($_POST['order'][0]['dir'])==='desc')?'DESC':'ASC';if(isset($orderMap[$col]))$orderBy=$orderMap[$col].' '.$dir;}
$rows=$db->query("SELECT s.*,a.applicant_no,a.applicant_name,a.applicant_status,v.vacancy_no,v.vacancy_title,i.interview_no,app.employee_no approved_no,app.full_name approved_name $base $w ORDER BY $orderBy LIMIT $start,$length",$p);
$data=array();$no=$start+1;foreach($rows as $r){$canDelete=in_array($r->selection_status,array('DRAFT','CANCELLED'),true);$act='<div class="sr-action"><button class="btn btn-info btn-xs btn-sr-detail" data-id="'.(int)$r->id.'"><i class="fa fa-eye"></i></button> <button class="btn btn-primary btn-xs btn-sr-edit" data-id="'.(int)$r->id.'"><i class="fa fa-pencil"></i></button> <button class="btn btn-success btn-xs btn-sr-status" data-id="'.(int)$r->id.'" data-status="APPROVED"><i class="fa fa-check"></i></button> <button class="btn btn-warning btn-xs btn-sr-status" data-id="'.(int)$r->id.'" data-status="SUBMITTED"><i class="fa fa-send"></i></button> <button class="btn btn-danger btn-xs btn-sr-delete" data-id="'.(int)$r->id.'" data-no="'.srd_h($r->selection_no).'"'.($canDelete?'':' disabled').'><i class="fa fa-trash"></i></button></div>';
  $data[]=array($no++,$act,'<strong>'.srd_h($r->selection_no).'</strong><br><small>'.srd_h($r->sap_reference?:'-').'</small>','<strong>'.srd_h($r->applicant_no.' - '.$r->applicant_name).'</strong><br><small>'.srd_h($r->applicant_status).'</small>','<strong>'.srd_h($r->vacancy_no?:'-').'</strong><br><small>'.srd_h($r->vacancy_title?:'-').'</small>','<span class="label label-info">'.srd_h($r->selection_stage).'</span><br><small>'.srd_h($r->selection_date).'</small>','<strong>'.number_format((float)$r->overall_score,2).'</strong><br><small>Rank '.srd_h($r->ranking_no?:'-').'</small>',srd_label($r->decision_result,'decision').'<br><small>'.srd_h($r->recommendation).'</small>',srd_label($r->selection_status).'<br><small>'.srd_h($r->approved_no?($r->approved_no.' - '.$r->approved_name):'-').'</small>','<strong>'.srd_h($r->currency).'</strong> '.number_format((float)$r->proposed_salary,2).'<br><small>'.srd_h($r->proposed_join_date?:'-').'</small>',srd_h($r->updated_by?:$r->created_by?:'-').'<br><small>'.srd_h($r->updated_at?:$r->created_at).'</small>');}
header('Content-Type: application/json; charset=utf-8');echo json_encode(array('draw'=>$draw,'recordsTotal'=>$total,'recordsFiltered'=>$total,'data'=>$data,'kpi'=>array('total'=>$kpi?(int)$kpi->total:0,'selected'=>$kpi?(int)$kpi->selected_count:0,'rejected'=>$kpi?(int)$kpi->rejected_count:0,'hold'=>$kpi?(int)$kpi->hold_count:0,'approved'=>$kpi?(int)$kpi->approved_count:0,'avg_score'=>$kpi?number_format((float)$kpi->avg_score,2):'0.00')));
?>
